import React, { useState } from 'react';

import silvanmerki from '../../assets/img/testimonials/silvanmerki.png';

const Quote = () => {
  const quotes = {
    0: {
      customer: 'Silvan Merki, CCO und Head Marketing/Communications, Implenia',
      quote: `Mit dem Contentboard von Benso haben wir jederzeit den Überblick über all unseren Content 
            in all unseren Marketing- und Kommunikationsinstrumenten. Es wird so zum rollierenden und laufend 
            aktualisierten Steuerungsinstrument für die integriert geführten Marketing- und Kommunikationsaktivitäten. 
            Viele nicht aufeinander abgestimmte Excel- und Power-Point-Planungen werden damit überflüssig. 
            Und Benso entwickelt das Tool laufend nach unseren Bedürfnissen weiter.`,
      image: silvanmerki,
    },
    // 1: {
    //     customer: "",
    //     quote: ``,
    //     image: ``
    // }
  };

  const [current, setCurrent] = useState(quotes[0]);

  const [active, setActive] = useState(0);

  const handleSetClick = (event) => {
    setCurrent(quotes[event.target.getAttribute('data-quote')]);
    setActive(event.target.getAttribute('data-quote'));
  };

  return (
    <div className={'quote-wrapper'}>
      <div className={'quote-content'}>
        <img
          className="quote-image"
          src={current.image}
          alt={current.customer}
        />
        <p>{current.quote}</p>
        <p>
          <i>{current.customer}</i>
        </p>
      </div>
      <div className={'quote-element'}>
        {Object.keys(quotes).map((index) => (
          <span
            className={` ${active === index ? 'quote-element-active' : ''}`}
            onClick={(event) => handleSetClick(event)}
            onKeyDown={(event) => handleSetClick(event)}
            data-quote={index}
            key={index}
          />
        ))}
      </div>
    </div>
  );
};

export default Quote;
